/**
 * 企业端通知中心 API — V3.7 §4.10
 * 对接 NotificationController（/notifications）
 */
import request from '@/api/request'

export interface Notification {
  id: number
  type: string
  title: string
  content: string
  refType?: string | null
  refId?: number | null
  isRead: boolean
  createdAt: string
}

export interface NotificationListParams {
  page?: number
  pageSize?: number
  type?: string
  isRead?: boolean
}

export const notificationApi = {
  /** 列表（分页 + 类型/未读筛选） */
  list: (params?: NotificationListParams) =>
    request.get<any, { total: number; items: Notification[] }>('/notifications', { params }),

  /** 未读数量 */
  unreadCount: () => request.get<any, { count: number }>('/notifications/unread-count'),

  /** 单条已读 */
  markRead: (id: number) => request.put<any, any>(`/notifications/${id}/read`),

  /** 全部已读 */
  markAllRead: () => request.put<any, any>('/notifications/read-all'),
}
