async function fetchNotifications() {
  loading.value = true
  try {
    const res = await notificationApi.list({ page: 1, pageSize: 100 })
    notifications.value = res?.items || []
  } catch (e: any) {
    message.error(e?.message || '加载通知失败')
    notifications.value = []
  } finally {
    loading.value = false
  }
}

async function markRead(id: number) {
  try {
    await notificationApi.markRead(id)
    const n = notifications.value.find((n) => n.id === id)
    if (n) n.isRead = true
  } catch (e: any) {
    message.error(e?.message || '操作失败')
  }
}

async function markAllRead() {
  try {
    await notificationApi.markAllRead()
    notifications.value.forEach((n) => (n.isRead = true))
    message.success('全部标记已读')
  } catch (e: any) {
    message.error(e?.message || '操作失败')
  }
}

function openNotification(n: Notification) {
  if (!n.isRead) markRead(n.id)
  // 跳转关联实体
  if (n.refType === 'task' && n.refId) router.push(`/task/${n.refId}`)
  else if (n.refType === 'project' && n.refId) router.push(`/project/${n.refId}`)
}

onMounted(fetchNotifications)
</script>

