import { useState, useEffect } from 'react'
import { View, Text, Button, Textarea } from '@tarojs/components'
import Taro, { useRouter } from '@tarojs/taro'
import { request } from '../../../../api/request'

interface Checkpoint {
  id: number
  name: string
  type: string
  plannedDate: string
  status: string
  description?: string
  revisionCount: number
}

export default function CheckpointSubmitPage() {
  const router = useRouter()
  const taskId = Number(router.params.taskId || 0)

  const [list, setList] = useState<Checkpoint[]>([])
  const [loading, setLoading] = useState(false)
  const [activeCp, setActiveCp] = useState<Checkpoint | null>(null)
  const [submitContent, setSubmitContent] = useState('')
  const [submitting, setSubmitting] = useState(false)

  const fetchList = async () => {
    if (!taskId) return
    setLoading(true)
    try {
      const res: any = await request({ url: `/tasks/${taskId}/checkpoints`, method: 'GET' })
      setList(res.data ?? res ?? [])
    } catch (e: any) {
      Taro.showToast({ title: e?.message || '加载失败', icon: 'none' })
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchList()
  }, [taskId])

  const handleSubmit = async () => {
    if (!activeCp) return
    if (!submitContent.trim()) {
      Taro.showToast({ title: '请填写检查内容', icon: 'none' })
      return
    }
    setSubmitting(true)
    try {
      await request({
        url: `/tasks/${taskId}/checkpoints/${activeCp.id}/submit`,
        method: 'POST',
        data: { submitContent },
      })
      Taro.showToast({ title: '已提交', icon: 'success' })
      setActiveCp(null)
      setSubmitContent('')
      fetchList()
    } catch (e: any) {
      Taro.showToast({ title: e?.message || '提交失败', icon: 'none' })
    } finally {
      setSubmitting(false)
    }
  }

  const statusText = (s: string) =>
    ({ pending: '⭕ 待检查', submitted: '📤 已提交', passed: '✅ 已通过', rejected: '❌ 不通过', overdue: '⏰ 已逾期' } as any)[s] || s
  const statusColor = (s: string) =>
    ({ pending: '#999', submitted: '#1890ff', passed: '#52c41a', rejected: '#ff4d4f', overdue: '#fa541c' } as any)[s] || '#999'
  const typeText = (t: string) => (t === 'progress_check' ? '进度检查' : '质量卡点')

  return (
    <View style={{ padding: '12px', minHeight: '100vh', background: '#f5f5f5' }}>
      {activeCp ? (
        <View style={{ background: '#fff', padding: '16px', borderRadius: '8px' }}>
          <Text style={{ fontSize: '16px', fontWeight: 'bold' }}>{activeCp.name}</Text>
          <View style={{ marginTop: '8px', color: '#666', fontSize: '13px' }}>
            <Text>{typeText(activeCp.type)} · 计划: {activeCp.plannedDate?.slice(0, 10)}</Text>
          </View>
          {activeCp.description && (
            <View style={{ marginTop: '8px', padding: '8px', background: '#f5f5f5', borderRadius: '4px', fontSize: '13px' }}>
              <Text>📝 {activeCp.description}</Text>
            </View>
          )}
          <Text style={{ display: 'block', marginTop: '16px', fontWeight: 'bold' }}>提交内容</Text>
          <Textarea
            placeholder='填写本次检查点完成情况'
            value={submitContent}
            maxlength={2000}
            onInput={(e: any) => setSubmitContent(e.detail.value)}
            style={{ width: '100%', minHeight: '120px', padding: '8px', marginTop: '8px', border: '1px solid #e8e8e8', borderRadius: '4px' }}
          />
          <View style={{ display: 'flex', gap: '8px', marginTop: '12px' }}>
            <Button style={{ flex: 1 }} onClick={() => setActiveCp(null)}>取消</Button>
            <Button type='primary' style={{ flex: 1 }} loading={submitting} onClick={handleSubmit}>提交</Button>
          </View>
        </View>
      ) : (
        <View>
          <Text style={{ fontSize: '14px', color: '#666', padding: '8px 4px' }}>
            共 {list.length} 个检查点
          </Text>
          {list.length === 0 && !loading && (
            <View style={{ padding: '40px 0', textAlign: 'center', color: '#999' }}>
              <Text>暂无检查点</Text>
            </View>
          )}
          {list.map((cp) => (
            <View
              key={cp.id}
              style={{
                background: '#fff',
                padding: '12px',
                borderRadius: '8px',
                marginBottom: '8px',
                borderLeft: `3px solid ${statusColor(cp.status)}`,
              }}
              onClick={() => cp.status === 'pending' || cp.status === 'rejected' ? setActiveCp(cp) : null}
            >
              <Text style={{ fontSize: '15px', fontWeight: 'bold' }}>{cp.name}</Text>
              <View style={{ marginTop: '4px', fontSize: '12px', color: '#666' }}>
                <Text>{typeText(cp.type)} · {cp.plannedDate?.slice(0, 10)}</Text>
              </View>
              <View style={{ marginTop: '4px' }}>
                <Text style={{ fontSize: '12px', color: statusColor(cp.status) }}>{statusText(cp.status)}</Text>
                {cp.revisionCount > 0 && <Text style={{ fontSize: '12px', color: '#faad14', marginLeft: '8px' }}>第 {cp.revisionCount + 1} 次</Text>}
              </View>
              {(cp.status === 'pending' || cp.status === 'rejected') && (
                <Text style={{ display: 'block', marginTop: '6px', fontSize: '12px', color: '#1890ff' }}>
                  点击提交 →
                </Text>
              )}
            </View>
          ))}
        </View>
      )}
    </View>
  )
}

import { useState, useEffect } from 'react'
import { View, Text, Button, Input, Textarea, Picker } from '@tarojs/components'
import Taro, { useRouter } from '@tarojs/taro'
import { request } from '../../../../api/request'

interface TaskIssue {
  id: number
  title: string
  type: string
  description: string
  status: string
  response?: string
  createdAt: string
}

const ISSUE_TYPES = [
  { value: 'requirement_unclear', label: '需求不明确' },
  { value: 'technical_block', label: '技术障碍' },
  { value: 'resource_missing', label: '资源缺失' },
  { value: 'other', label: '其他' },
]

export default function IssueReportPage() {
  const router = useRouter()
  const taskId = Number(router.params.taskId || 0)

  const [list, setList] = useState<TaskIssue[]>([])
  const [showForm, setShowForm] = useState(false)

  const [title, setTitle] = useState('')
  const [typeIdx, setTypeIdx] = useState(0)
  const [description, setDescription] = useState('')
  const [submitting, setSubmitting] = useState(false)

  const fetchList = async () => {
    if (!taskId) return
    try {
      const res: any = await request({ url: `/tasks/${taskId}/issues`, method: 'GET' })
      setList(res.data ?? res ?? [])
    } catch (e: any) {
      Taro.showToast({ title: e?.message || '加载失败', icon: 'none' })
    }
  }

  useEffect(() => {
    fetchList()
  }, [taskId])

  const handleSubmit = async () => {
    if (!title.trim()) {
      Taro.showToast({ title: '请填写标题', icon: 'none' })
      return
    }
    if (description.length < 50) {
      Taro.showToast({ title: '描述至少 50 字', icon: 'none' })
      return
    }
    setSubmitting(true)
    try {
      await request({
        url: `/tasks/${taskId}/issues`,
        method: 'POST',
        data: {
          title: title.trim(),
          type: ISSUE_TYPES[typeIdx].value,
          description: description.trim(),
        },
      })
      Taro.showToast({ title: '已上报', icon: 'success' })
      setTitle('')
      setDescription('')
      setTypeIdx(0)
      setShowForm(false)
      fetchList()
    } catch (e: any) {
      Taro.showToast({ title: e?.message || '上报失败', icon: 'none' })
    } finally {
      setSubmitting(false)
    }
  }

  const statusText = (s: string) =>
    ({ open: '🔴 待响应', in_progress: '🟡 处理中', resolved: '✅ 已解决', closed: '⚪ 已关闭' } as any)[s] || s
  const typeText = (t: string) => ISSUE_TYPES.find((x) => x.value === t)?.label || t

  return (
    <View style={{ padding: '12px', minHeight: '100vh', background: '#f5f5f5' }}>
      {showForm ? (
        <View style={{ background: '#fff', padding: '16px', borderRadius: '8px' }}>
          <Text style={{ fontSize: '16px', fontWeight: 'bold' }}>上报阻塞问题</Text>

          <Text style={{ display: 'block', marginTop: '12px', fontSize: '13px', color: '#666' }}>问题标题</Text>
          <Input
            placeholder='简要描述遇到的问题'
            value={title}
            maxlength={100}
            onInput={(e: any) => setTitle(e.detail.value)}
            style={{ width: '100%', padding: '8px', marginTop: '4px', border: '1px solid #e8e8e8', borderRadius: '4px' }}
          />

          <Text style={{ display: 'block', marginTop: '12px', fontSize: '13px', color: '#666' }}>问题类型</Text>
          <Picker mode='selector' range={ISSUE_TYPES.map((x) => x.label)} value={typeIdx} onChange={(e: any) => setTypeIdx(Number(e.detail.value))}>
            <View style={{ padding: '10px', marginTop: '4px', border: '1px solid #e8e8e8', borderRadius: '4px' }}>
              <Text>{ISSUE_TYPES[typeIdx].label}</Text>
            </View>
          </Picker>

          <Text style={{ display: 'block', marginTop: '12px', fontSize: '13px', color: '#666' }}>详细描述（50-500字）</Text>
          <Textarea
            placeholder='详细描述问题和遇到的阻塞'
            value={description}
            maxlength={500}
            onInput={(e: any) => setDescription(e.detail.value)}
            style={{ width: '100%', minHeight: '120px', padding: '8px', marginTop: '4px', border: '1px solid #e8e8e8', borderRadius: '4px' }}
          />
          <Text style={{ fontSize: '12px', color: '#999' }}>{description.length}/500</Text>

          <View style={{ display: 'flex', gap: '8px', marginTop: '12px' }}>
            <Button style={{ flex: 1 }} onClick={() => setShowForm(false)}>取消</Button>
            <Button type='primary' style={{ flex: 1 }} loading={submitting} onClick={handleSubmit}>上报</Button>
          </View>
        </View>
      ) : (
        <View>
          <Button type='primary' onClick={() => setShowForm(true)} style={{ marginBottom: '12px' }}>+ 上报新问题</Button>

          <Text style={{ display: 'block', fontSize: '14px', color: '#666', padding: '8px 4px' }}>
            历史问题 ({list.length})
          </Text>

          {list.length === 0 && (
            <View style={{ padding: '40px 0', textAlign: 'center', color: '#999' }}>
              <Text>暂无问题</Text>
            </View>
          )}

          {list.map((i) => (
            <View key={i.id} style={{ background: '#fff', padding: '12px', borderRadius: '8px', marginBottom: '8px' }}>
              <Text style={{ fontSize: '14px', fontWeight: 'bold' }}>{i.title}</Text>
              <View style={{ marginTop: '4px' }}>
                <Text style={{ fontSize: '12px', color: '#1890ff' }}>{typeText(i.type)}</Text>
                <Text style={{ fontSize: '12px', color: '#999', marginLeft: '8px' }}>{i.createdAt?.slice(5, 16).replace('T', ' ')}</Text>
              </View>
              <Text style={{ display: 'block', marginTop: '6px', fontSize: '13px', color: '#333' }}>{i.description}</Text>
              <View style={{ marginTop: '6px' }}>
                <Text style={{ fontSize: '13px' }}>{statusText(i.status)}</Text>
              </View>
              {i.response && (
                <View style={{ marginTop: '8px', padding: '6px 8px', background: '#f5f5f5', borderRadius: '4px' }}>
                  <Text style={{ fontSize: '12px', color: '#666' }}>💬 企业回复：</Text>
                  <Text style={{ fontSize: '13px' }}>{i.response}</Text>
                </View>
              )}
            </View>
          ))}
        </View>
      )}
    </View>
  )
}

import { useState, useEffect } from 'react'
import { View, Text, Button, Textarea, ScrollView } from '@tarojs/components'
import Taro, { useRouter } from '@tarojs/taro'
import { request } from '../../../../api/request'

interface Comment {
  id: number
  parentId?: number | null
  authorType: 'company_user' | 'worker'
  authorId: number
  author?: { name?: string }
  content: string
  isImportant: boolean
  createdAt: string
}

export default function CommentsPage() {
  const router = useRouter()
  const taskId = Number(router.params.taskId || 0)

  const [all, setAll] = useState<Comment[]>([])
  const [loading, setLoading] = useState(false)
  const [content, setContent] = useState('')
  const [submitting, setSubmitting] = useState(false)

  const fetchList = async () => {
    if (!taskId) return
    setLoading(true)
    try {
      const res: any = await request({
        url: `/tasks/${taskId}/comments`,
        method: 'GET',
        data: { page: 1, pageSize: 200 },
      })
      const payload = res.data ?? res
      setAll(payload.items || payload || [])
    } catch (e: any) {
      Taro.showToast({ title: e?.message || '加载失败', icon: 'none' })
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchList()
  }, [taskId])

  const handleSubmit = async () => {
    if (!content.trim()) {
      Taro.showToast({ title: '请输入评论', icon: 'none' })
      return
    }
    setSubmitting(true)
    try {
      await request({
        url: `/tasks/${taskId}/comments`,
        method: 'POST',
        data: { content: content.trim() },
      })
      setContent('')
      fetchList()
    } catch (e: any) {
      Taro.showToast({ title: e?.message || '发送失败', icon: 'none' })
    } finally {
      setSubmitting(false)
    }
  }

  const topComments = all.filter((c) => !c.parentId)
  const repliesOf = (pid: number) => all.filter((c) => c.parentId === pid)
  const formatTime = (t: string) => t?.slice(5, 16).replace('T', ' ') || ''

  return (
    <View style={{ height: '100vh', display: 'flex', flexDirection: 'column', background: '#f5f5f5' }}>
      <ScrollView scrollY style={{ flex: 1, padding: '12px' }}>
        {topComments.length === 0 && !loading && (
          <View style={{ padding: '40px 0', textAlign: 'center', color: '#999' }}>
            <Text>还没有人发言，开始讨论吧</Text>
          </View>
        )}

        {topComments.map((c) => (
          <View
            key={c.id}
            style={{
              background: c.isImportant ? '#fffbe6' : '#fff',
              padding: '12px',
              borderRadius: '8px',
              marginBottom: '8px',
              borderLeft: c.isImportant ? '3px solid #faad14' : '2px solid #f0f0f0',
            }}
          >
            <View style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
              <Text style={{ fontSize: '13px', fontWeight: 'bold' }}>
                {c.author?.name || (c.authorType === 'company_user' ? `企业#${c.authorId}` : `零工#${c.authorId}`)}
              </Text>
              <Text style={{ fontSize: '11px', color: '#1890ff' }}>
                {c.authorType === 'company_user' ? '[企业]' : '[零工]'}
              </Text>
              {c.isImportant && <Text style={{ fontSize: '11px', color: '#faad14' }}>⭐ 重要</Text>}
              <Text style={{ fontSize: '11px', color: '#999', marginLeft: 'auto' }}>{formatTime(c.createdAt)}</Text>
            </View>
            <Text style={{ display: 'block', marginTop: '6px', fontSize: '13px', lineHeight: '1.6' }}>{c.content}</Text>

            {repliesOf(c.id).map((r) => (
              <View
                key={r.id}
                style={{ marginTop: '8px', marginLeft: '16px', padding: '8px', background: '#f9f9f9', borderRadius: '4px' }}
              >
                <Text style={{ fontSize: '12px', fontWeight: 'bold' }}>
                  {r.author?.name || (r.authorType === 'company_user' ? '企业' : '零工')}:
                </Text>
                <Text style={{ display: 'block', fontSize: '12px', marginTop: '2px' }}>{r.content}</Text>
              </View>
            ))}
          </View>
        ))}
      </ScrollView>

      <View style={{ padding: '8px', background: '#fff', borderTop: '1px solid #e8e8e8' }}>
        <Textarea
          placeholder='发表评论...'
          value={content}
          maxlength={1000}
          onInput={(e: any) => setContent(e.detail.value)}
          style={{ width: '100%', minHeight: '60px', padding: '8px', border: '1px solid #e8e8e8', borderRadius: '4px' }}
        />
        <View style={{ display: 'flex', justifyContent: 'flex-end', marginTop: '6px' }}>
          <Button type='primary' size='mini' loading={submitting} onClick={handleSubmit}>
            发送
          </Button>
        </View>
      </View>
    </View>
  )
}

