/**
 * V3.7 Step 5.1 — 风险等级计算 Cron
 * 每小时触发：对进行中的任务/项目重新计算 riskLevel（red/yellow/green）
 *  - days_to_deadline <= 2 && progress < 80%  → red
 *  - days_to_deadline <= 5 && progress < 70%  → yellow
 *  - else                                     → green
 *
 * 等级变化时写入 company_notification('risk_alert')，供前端轮询展示。
 */
import { Injectable, Logger } from '@nestjs/common';
import { Cron, CronExpression } from '@nestjs/schedule';
import { PrismaService } from '../../prisma/prisma.service';
import { CompanyNotificationService } from '../notification/company-notification.service';

type Level = 'green' | 'yellow' | 'red';

@Injectable()
export class RiskLevelCron {
  private readonly logger = new Logger(RiskLevelCron.name);

  constructor(
    private readonly prisma: PrismaService,
    private readonly notify: CompanyNotificationService,
  ) {}

  private computeLevel(daysLeft: number, progress: number): Level {
    if (daysLeft <= 2 && progress < 80) return 'red';
    if (daysLeft <= 5 && progress < 70) return 'yellow';
    return 'green';
  }

  private daysBetween(future: Date, now: Date = new Date()) {
    const diff = future.getTime() - now.getTime();
    return Math.floor(diff / 86400_000);
  }

  @Cron(CronExpression.EVERY_HOUR, { name: 'v3.7_risk_level' })
  async runScheduled() {
    await this.runOnce();
  }

  /** 供测试直接调用 */
  async runOnce() {
    const stats = { taskChecked: 0, taskChanged: 0, projectChecked: 0, projectChanged: 0 };

    // ========= 任务层面 =========
    const tasks = await this.prisma.task.findMany({
      where: { status: 'in_progress', endDate: { not: null } },
      select: {
        id: true, title: true, endDate: true, riskLevel: true,
        createdBy: true, companyId: true,
        roles: {
          select: {
            assignments: { select: { progress: true, status: true } },
          },
        },
      },
    });

    for (const t of tasks) {
      stats.taskChecked++;
      if (!t.endDate) continue;
      const daysLeft = this.daysBetween(t.endDate);

      // 平均进度（仅 accepted / completed）
      const progs = t.roles.flatMap((r) =>
        r.assignments.filter((a) => ['accepted', 'completed'].includes(a.status)).map((a) => a.progress),
      );
      const avgProgress = progs.length > 0 ? Math.round(progs.reduce((a, b) => a + b, 0) / progs.length) : 0;

      const nextLevel = this.computeLevel(daysLeft, avgProgress);
      if (nextLevel === t.riskLevel) continue;

      stats.taskChanged++;
      await this.prisma.task.update({
        where: { id: t.id },
        data: { riskLevel: nextLevel as any },
      });

      if ((nextLevel === 'red' || nextLevel === 'yellow') && t.companyId && t.createdBy) {
        await this.notify.create({
          companyId: Number(t.companyId),
          userId: Number(t.createdBy),
          type: 'risk_alert',
          title: `任务风险升级：${t.title}`,
          content: `任务「${t.title}」风险等级已变更为 ${nextLevel.toUpperCase()}（剩余 ${daysLeft} 天 / 进度 ${avgProgress}%）`,
          refType: 'task',
          refId: Number(t.id),
        });
      }
    }

    // ========= 项目层面 =========
    const projects = await this.prisma.project.findMany({
      where: {
        status: { in: ['planning', 'in_progress'] as any },
        expectedDeliveryDate: { not: null },
      },
      select: {
        id: true, name: true, expectedDeliveryDate: true, riskLevel: true,
        managerId: true, companyId: true,
      },
    });

    for (const p of projects) {
      stats.projectChecked++;
      if (!p.expectedDeliveryDate) continue;
      const daysLeft = this.daysBetween(p.expectedDeliveryDate);

      // 项目进度 = 关联任务 roleAssignment 平均
      const agg = await this.prisma.task.findMany({
        where: { projectId: p.id },
        select: {
          roles: { select: { assignments: { select: { progress: true, status: true } } } },
        },
      });
      const progs = agg.flatMap((t) =>
        t.roles.flatMap((r) =>
          r.assignments.filter((a) => ['accepted', 'completed'].includes(a.status)).map((a) => a.progress),
        ),
      );
      const avgProgress = progs.length > 0 ? Math.round(progs.reduce((a, b) => a + b, 0) / progs.length) : 0;

      const nextLevel = this.computeLevel(daysLeft, avgProgress);
      if (nextLevel === p.riskLevel) continue;

      stats.projectChanged++;
      await this.prisma.project.update({
        where: { id: p.id },
        data: { riskLevel: nextLevel as any },
      });

      if ((nextLevel === 'red' || nextLevel === 'yellow') && p.managerId) {
        await this.notify.create({
          companyId: Number(p.companyId),
          userId: Number(p.managerId),
          type: 'risk_alert',
          title: `项目风险升级：${p.name}`,
          content: `项目「${p.name}」风险等级已变更为 ${nextLevel.toUpperCase()}（剩余 ${daysLeft} 天 / 进度 ${avgProgress}%）`,
          refType: 'project',
          refId: Number(p.id),
        });
      }
    }

    this.logger.log(`risk-level runOnce: ${JSON.stringify(stats)}`);
    return stats;
  }
}

/**
 * V3.7 Step 5.2 — 问题 SLA 监控
 * 每 15 分钟扫描 TaskIssue：
 *   - status='open' AND firstResponseAt IS NULL AND createdAt < NOW()-24h AND slaBreached=false
 *   → 置 slaBreached=true，通知 task.createdBy
 */
import { Injectable, Logger } from '@nestjs/common';
import { Cron } from '@nestjs/schedule';
import { PrismaService } from '../../prisma/prisma.service';
import { CompanyNotificationService } from '../notification/company-notification.service';

@Injectable()
export class SlaMonitorCron {
  private readonly logger = new Logger(SlaMonitorCron.name);

  constructor(
    private readonly prisma: PrismaService,
    private readonly notify: CompanyNotificationService,
  ) {}

  @Cron('*/15 * * * *', { name: 'v3.7_sla_monitor' })
  async runScheduled() {
    await this.runOnce();
  }

  async runOnce() {
    const threshold24h = new Date(Date.now() - 24 * 3600_000);

    const breached = await this.prisma.taskIssue.findMany({
      where: {
        status: 'open',
        firstResponseAt: null,
        createdAt: { lt: threshold24h },
        slaBreached: false,
      },
      select: {
        id: true, taskId: true, title: true,
        task: { select: { title: true, createdBy: true, companyId: true } },
      },
    });

    for (const i of breached) {
      await this.prisma.taskIssue.update({
        where: { id: i.id },
        data: { slaBreached: true },
      });

      if (i.task?.companyId && i.task?.createdBy) {
        await this.notify.create({
          companyId: Number(i.task.companyId),
          userId: Number(i.task.createdBy),
          type: 'sla_breach',
          title: `问题 SLA 超时：${i.title}`,
          content: `任务「${i.task.title}」的问题「${i.title}」已超过 24 小时未响应`,
          refType: 'task',
          refId: Number(i.taskId),
        });
      }
    }

    this.logger.log(`sla-monitor runOnce: breached=${breached.length}`);
    return { breached: breached.length };
  }
}

/**
 * V3.7 Step 5.3 — 检查点逾期扫描
 * 每天 00:30：将 plannedDate < TODAY 且 status='pending' 的检查点置为 overdue
 * 通知：检查点 reviewer（企业用户）
 */
import { Injectable, Logger } from '@nestjs/common';
import { Cron } from '@nestjs/schedule';
import { PrismaService } from '../../prisma/prisma.service';
import { CompanyNotificationService } from '../notification/company-notification.service';

@Injectable()
export class CheckpointOverdueCron {
  private readonly logger = new Logger(CheckpointOverdueCron.name);

  constructor(
    private readonly prisma: PrismaService,
    private readonly notify: CompanyNotificationService,
  ) {}

  @Cron('30 0 * * *', { name: 'v3.7_checkpoint_overdue' })
  async runScheduled() {
    await this.runOnce();
  }

  async runOnce() {
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    const overdueList = await this.prisma.taskCheckpoint.findMany({
      where: {
        status: 'pending',
        plannedDate: { lt: today },
      },
      select: {
        id: true, taskId: true, name: true, reviewerId: true,
        task: { select: { title: true, companyId: true, createdBy: true } },
      },
    });

    for (const cp of overdueList) {
      await this.prisma.taskCheckpoint.update({
        where: { id: cp.id },
        data: { status: 'overdue' as any },
      });

      // 通知 reviewer（或退回给 createdBy）
      const notifyUserId = cp.reviewerId ?? cp.task?.createdBy;
      if (cp.task?.companyId && notifyUserId) {
        await this.notify.create({
          companyId: Number(cp.task.companyId),
          userId: Number(notifyUserId),
          type: 'checkpoint',
          title: `检查点已逾期：${cp.name}`,
          content: `任务「${cp.task.title}」的检查点「${cp.name}」已超过计划日期`,
          refType: 'task',
          refId: Number(cp.taskId),
        });
      }
    }

    this.logger.log(`checkpoint-overdue runOnce: overdue=${overdueList.length}`);
    return { overdue: overdueList.length };
  }
}

/**
 * V3.7 Step 5.4 — 日报缺失扫描
 * 每天 09:00：检查进行中任务，若零工连续 3 个自然日未提交 progress_updates
 * → 通知零工（写 company_notification type='daily_missing'）
 * → 通知任务发起人（企业 PM）
 *
 * 简化版：连续 3 天 ≈ 3*24h；不排除周末（实际业务按自然日即可）
 */
import { Injectable, Logger } from '@nestjs/common';
import { Cron } from '@nestjs/schedule';
import { PrismaService } from '../../prisma/prisma.service';
import { CompanyNotificationService } from '../notification/company-notification.service';

@Injectable()
export class DailyMissingCron {
  private readonly logger = new Logger(DailyMissingCron.name);

  constructor(
    private readonly prisma: PrismaService,
    private readonly notify: CompanyNotificationService,
  ) {}

  @Cron('0 9 * * *', { name: 'v3.7_daily_missing' })
  async runScheduled() {
    await this.runOnce();
  }

  async runOnce() {
    const threshold = new Date(Date.now() - 3 * 86400_000);

    // 进行中任务下 accepted 且进度未到 100% 的 assignment
    const activeAssignments = await this.prisma.roleAssignment.findMany({
      where: {
        status: 'accepted',
        progress: { lt: 100 },
        taskRole: { task: { status: 'in_progress' } },
      },
      select: {
        id: true, workerId: true,
        taskRole: {
          select: {
            task: { select: { id: true, title: true, companyId: true, createdBy: true } },
          },
        },
      },
    });

    // 获取这些 assignment 的最近一次 progressUpdate
    const ids = activeAssignments.map((a) => a.id);
    if (ids.length === 0) {
      this.logger.log('daily-missing runOnce: no active assignments');
      return { missing: 0 };
    }

    const recentUpdates = await this.prisma.progressUpdate.groupBy({
      by: ['assignmentId'],
      where: { assignmentId: { in: ids } },
      _max: { createdAt: true },
    });
    const latestMap = new Map<string, Date | null>();
    for (const r of recentUpdates) {
      latestMap.set(String(r.assignmentId), (r._max as any).createdAt);
    }

    const missingByTask = new Map<string, { task: any; workerIds: Set<number> }>();

    for (const a of activeAssignments) {
      const last = latestMap.get(String(a.id));
      if (last && last > threshold) continue; // 最近 3 天有更新

      const task = a.taskRole?.task;
      if (!task) continue;
      const key = String(task.id);
      if (!missingByTask.has(key)) missingByTask.set(key, { task, workerIds: new Set() });
      missingByTask.get(key)!.workerIds.add(Number(a.workerId));
    }

    let notified = 0;
    for (const { task, workerIds } of missingByTask.values()) {
      // 通知 PM
      if (task.companyId && task.createdBy) {
        await this.notify.create({
          companyId: Number(task.companyId),
          userId: Number(task.createdBy),
          type: 'daily_missing',
          title: `日报缺失提醒：${task.title}`,
          content: `任务「${task.title}」有 ${workerIds.size} 名零工连续 3 天未提交日报`,
          refType: 'task',
          refId: Number(task.id),
        });
        notified++;
      }
      // TODO: 通知零工侧需走微信订阅消息（本 Phase 不实现）
    }

    this.logger.log(`daily-missing runOnce: tasksNotified=${notified}`);
    return { missing: notified };
  }
}

/**
 * V3.7 Step 5.5 — 里程碑到期扫描
 * 每天 00:30：
 *   - plannedDate < NOW AND status='pending'  → status='overdue' + 红色通知
 *   - plannedDate - NOW in (0, 3d] AND status='pending' AND !reminderSent → T-3 提醒
 *
 * 注：Milestone 表无 reminderSent 字段，此处用 company_notification 查重（同一 milestone + type）。
 */
import { Injectable, Logger } from '@nestjs/common';
import { Cron } from '@nestjs/schedule';
import { PrismaService } from '../../prisma/prisma.service';
import { CompanyNotificationService } from '../notification/company-notification.service';

@Injectable()
export class MilestoneRemindCron {
  private readonly logger = new Logger(MilestoneRemindCron.name);

  constructor(
    private readonly prisma: PrismaService,
    private readonly notify: CompanyNotificationService,
  ) {}

  @Cron('30 0 * * *', { name: 'v3.7_milestone_remind' })
  async runScheduled() {
    await this.runOnce();
  }

  async runOnce() {
    const now = new Date();
    const in3Days = new Date(now.getTime() + 3 * 86400_000);

    const pending = await this.prisma.milestone.findMany({
      where: { status: 'pending' as any },
      select: {
        id: true, name: true, plannedDate: true, projectId: true,
        project: { select: { name: true, managerId: true, companyId: true } },
      },
    });

    let overdueCount = 0;
    let remindedCount = 0;

    for (const m of pending) {
      if (!m.plannedDate || !m.project?.managerId || !m.project?.companyId) continue;
      const companyId = Number(m.project.companyId);
      const managerId = Number(m.project.managerId);

      if (m.plannedDate < now) {
        await this.prisma.milestone.update({
          where: { id: m.id },
          data: { status: 'overdue' as any },
        });
        await this.notify.create({
          companyId, userId: managerId, type: 'milestone_remind',
          title: `里程碑已逾期：${m.name}`,
          content: `项目「${m.project.name}」的里程碑「${m.name}」已超过计划日期`,
          refType: 'project', refId: Number(m.projectId),
        });
        overdueCount++;
      } else if (m.plannedDate <= in3Days) {
        // T-3 提醒：用 company_notification 查重（相同 milestone + type 24h 内只发一次）
        const recent = await this.prisma.companyNotification.findFirst({
          where: {
            userId: BigInt(managerId),
            type: 'milestone_remind',
            refType: 'milestone',
            refId: BigInt(m.id),
            createdAt: { gt: new Date(now.getTime() - 24 * 3600_000) },
          },
          select: { id: true },
        });
        if (recent) continue;

        await this.notify.create({
          companyId, userId: managerId, type: 'milestone_remind',
          title: `里程碑即将到期：${m.name}`,
          content: `项目「${m.project.name}」的里程碑「${m.name}」将在 ${Math.ceil((m.plannedDate.getTime() - now.getTime()) / 86400_000)} 天后到期`,
          refType: 'milestone', refId: Number(m.id),
        });
        remindedCount++;
      }
    }

    this.logger.log(`milestone-remind runOnce: overdue=${overdueCount} reminded=${remindedCount}`);
    return { overdue: overdueCount, reminded: remindedCount };
  }
}

